  /// Get all animals
  static List<Animal> getAllAnimals() => _animals;

  /// Get animal by ID
  static Animal? getAnimalById(int id) {
    try {
      return _animals.firstWhere((animal) => animal.id == id);
    } catch (e) {
      return null;
    }
  }

  /// Smart search - matches against multiple fields
  static Animal? smartMatch(String query) {
    if (query.isEmpty) return null;
    
    final normalizedQuery = query.toLowerCase().trim();
    
    // Try exact match first
    for (var animal in _animals) {
      if (animal.englishName.toLowerCase() == normalizedQuery ||
          animal.arabicName == query ||
          animal.scientificName.toLowerCase() == normalizedQuery) {
        return animal;
      }
    }
    
    // Try partial match
    for (var animal in _animals) {
      if (animal.englishName.toLowerCase().contains(normalizedQuery) ||
          animal.arabicName.contains(query) ||
          animal.scientificName.toLowerCase().contains(normalizedQuery)) {
        return animal;
      }
    }
    
    // Try word match
    final words = normalizedQuery.split(' ');
    for (var animal in _animals) {
      final animalText = '${animal.englishName} ${animal.arabicName} ${animal.scientificName}'.toLowerCase();
      if (words.every((word) => animalText.contains(word))) {
        return animal;
      }
    }
    
    return null;
  }

  /// Search animals by category
  static List<Animal> searchByCategory(String category) {
    return _animals.where((animal) => 
      animal.category.toLowerCase().contains(category.toLowerCase())
    ).toList();
  }

  /// Search animals by conservation status
  static List<Animal> searchByConservation(String status) {
    return _animals.where((animal) => 
      animal.conservation.toLowerCase().contains(status.toLowerCase())
    ).toList();
  }

  /// Get total count
  static int getTotalCount() => _animals.length;
  
  /// Get categories
  static List<String> getCategories() {
    return _animals.map((a) => a.category).toSet().toList()..sort();
  }
}